        id: Date.now(),
        type: 'user',
        content: userMessage,
      },
    ]);

    setIsTyping(true);

    try {
      // Secure AI query with security headers
      const requestId = crypto.randomUUID();
      const aiResponse = await axiosInstance.post(
        '/ai/reya/query/',
