      // Verify user has proper permissions first
      const permissions = JSON.parse(localStorage.getItem('user_permissions') || '{}');
      if (!permissions.generate_documents) {
        setMessages((prev) => [
          ...prev,
          {
            id: Date.now(),
            type: 'assistant',
            content: `≡ƒöÆ **PERMISSION DENIED**\n\nYou do not have authorization to generate this document type. Please contact your administrator for access.\n\nThis security check ensures compliance with legal practice regulations.`,
          },
        ]);
        setIsTyping(false);
        return;
      }

      // Generate document with proper security headers
      const response = await axiosInstance.post(
        '/documents/generate/',
        {
          type: documentType,
          context: contextData,
          format: 'docx',
          encrypted: true,
        },
        {
          headers: {
            'X-Security-Context': 'legal-document-generation',
            'X-Request-ID': crypto.randomUUID(),
          },
        }
      );

      const document = response.data;

      // Secure download with one-time token
      const link = document.createElement('a');
      link.href = `${document.download_url}?token=${document.download_token}`;
      link.download = document.filename;
      link.rel = 'noopener noreferrer';
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);

      // Revoke token immediately after download
      await axiosInstance.post('/documents/revoke-token/', { token: document.download_token });

      setMessages((prev) => [
        ...prev,
        {
          id: Date.now(),
          type: 'assistant',
          content: `Γ£à **${documentType.toUpperCase()} GENERATED**\n\n≡ƒöÆ **Security Status:** AES-256 Encrypted\n≡ƒôä **File:** ${document.filename}\n≡ƒôè **Pages:** ${document.page_count}\nΓ£ì∩╕Å **Auto-filled:** ${Object.keys(contextData || {}).length} fields\n\nAll client and case data has been cross-referenced for consistency. Document complies with standard legal formatting requirements.\n\nΓÜá∩╕Å Always review legal documents before finalizing.`,
