          ],
          suggestions: [
            { label: 'Generate another document', action: 'generate_more' },
            { label: 'Email secure link to client', action: 'email_doc' },
          ],
        },
      ]);
    } catch (error) {
      setMessages((prev) => [
        ...prev,
        {
          id: Date.now(),
          type: 'assistant',
          content: `ΓÜá∩╕Å Document generation failed. Security protocols require verified session.\n\nPlease log out and back in to refresh your security token.`,
