/**
 * AppWrite Configuration Validation Script
 * Run with: node src/config/validate-config.js
 *
 * Validates that all required environment variables are set
 * for AppWrite production deployment.
 */

const fs = require('fs');
const path = require('path');

function validateConfig() {
  const envPath = path.resolve(__dirname, '../../.env');
  const errors = [];
  const warnings = [];
  const success = [];

  console.log('≡ƒöì Validating AppWrite Configuration\n');

  // Check if .env exists
  if (!fs.existsSync(envPath)) {
    console.error('Γ¥î .env file not found at:', envPath);
    console.error('   Copy .env.example to .env and configure your settings.');
    process.exit(1);
  }

  // Read .env file
  const envContent = fs.readFileSync(envPath, 'utf8');
  const envLines = envContent
    .split('\n')
    .filter((line) => line.trim() && !line.trim().startsWith('#'));

  const envVars = {};
  envLines.forEach((line) => {
    const [key, ...valueParts] = line.split('=');
    if (key) {
      envVars[key.trim()] = valueParts
        .join('=')
        .trim()
        .replace(/^["']|["']$/g, '');
    }
  });

  // Check required variables
  const required = [
    'REACT_APP_USE_APPWRITE',
    'REACT_APP_APPWRITE_ENDPOINT',
    'REACT_APP_APPWRITE_PROJECT_ID',
    'REACT_APP_APPWRITE_DATABASE_ID',
  ];

  console.log('Required Environment Variables:\n');

  required.forEach((key) => {
    const value = envVars[key];
    if (!value) {
      errors.push(key);
      console.log(`  Γ£ù ${key}: Missing`);
    } else {
      if (key === 'REACT_APP_USE_APPWRITE') {
        if (value === 'true') {
          success.push(key);
          console.log(`  Γ£ô ${key}: ${value} (Production Mode)`);
        } else {
          warnings.push(key);
          console.log(`  ΓÜá ${key}: ${value} (Standalone Mode - No database)`);
        }
      } else {
        success.push(key);
        console.log(`  Γ£ô ${key}: Set`);
      }
    }
  });

  // Check security settings
  console.log('\nSecurity Settings:\n');

  const securityVars = ['REACT_APP_SESSION_COOKIE_SECURE', 'REACT_APP_SESSION_COOKIE_SAMESITE'];

  securityVars.forEach((key) => {
    const value = envVars[key];
    if (value) {
      console.log(`  Γ£ô ${key}: ${value}`);
    } else {
      warnings.push(key);
      console.log(`  ΓÜá ${key}: Not set (using defaults)`);
    }
  });

  // Summary
  console.log('\n' + '='.repeat(50));
  console.log('VALIDATION SUMMARY');
  console.log('='.repeat(50) + '\n');

  if (errors.length > 0) {
    console.error('Γ¥î ERRORS (must fix):');
    errors.forEach((err) => console.error(`   - ${err}`));
    console.error('\nPlease set all required environment variables.');
    process.exit(1);
  }

  if (warnings.length > 0) {
    console.warn('ΓÜá∩╕Å  WARNINGS:');
    warnings.forEach((warn) => console.warn(`   - ${warn}`));
    console.log();
  }

  if (envVars.REACT_APP_USE_APPWRITE === 'true') {
    console.log('Γ£à Configuration is valid for PRODUCTION mode');
    console.log('\nAppWrite will be used as the backend.');
    console.log('Make sure you have:');
    console.log('  1. Created all collections (see appwrite_setup.md)');
    console.log('  2. Set up proper security permissions');
    console.log('  3. Enabled storage bucket for documents');
  } else {
    console.log('Γ£à Configuration is valid for STANDALONE mode');
    console.log('\nApp will use localStorage for data storage.');
    console.log('Set REACT_APP_USE_APPWRITE=true to enable AppWrite.');
  }

  console.log('\n' + '='.repeat(50) + '\n');
  process.exit(0);
}

validateConfig();

import { createContext, useEffect, useMemo, useState } from 'react';
import { notification } from 'antd';
import axiosInstance from '../axiosConfig';

const AuthContext = createContext(null);

const parseStoredUser = () => {
  try {
    const encrypted = localStorage.getItem('userInfo_encrypted');
    if (encrypted) {
      // TODO: In production, derive key from user password
      // For now, fallback to unencrypted for demo
      return JSON.parse(localStorage.getItem('userInfo') || 'null');
    }
    return JSON.parse(localStorage.getItem('userInfo') || 'null');
  } catch (error) {
    return null;
  }
};

const normalizeRegisterPayload = (formData, userType) => {
  const lowered = Object.entries(formData || {}).reduce((acc, [key, value]) => {
    acc[key.toLowerCase()] = typeof value === 'string' ? value.trim() : value;
    return acc;
  }, {});

  if (lowered.password !== lowered['confirm password']) {
    throw new Error('Passwords do not match');
  }

  if (userType === 'organization') {
    return {
      email: lowered.email,
      username: lowered['organization name'] || lowered.email,
      password: lowered.password,
      role: 'organization',
      phone_number: lowered['phone number'] || '',
      alternative_phone_number: lowered['alternative phone number'] || '',
      address: lowered.address || '',
      occupation: 'Organization',
    };
  }

  if (userType === 'law firm') {
    return {
      email: lowered.email,
      username: lowered['law firm name'] || lowered.email,
      password: lowered.password,
      role: 'firm',
      phone_number: lowered['phone number'] || '',
      alternative_phone_number: lowered['alternative phone number'] || '',
      address: lowered.address || '',
      occupation: 'Law Firm',
    };
  }

  return {
    email: lowered.email,
    username: lowered['full name'] || lowered.email,
    password: lowered.password,
    role: lowered['is advocate'] === 'true' ? 'advocate' : 'individual',
    phone_number: lowered['phone number'] || '',
    alternative_phone_number: lowered['alternative phone number'] || '',
    id_passport_number: lowered['id number or passport number'] || '',
    marital_status: lowered['marital status'] || '',
    occupation: lowered.occupation || '',
    address: lowered.address || '',
    date_of_birth: lowered['date of birth'] || '',
  };
};

const AuthProvider = ({ children }) => {
  const [user, setUser] = useState(parseStoredUser);

  useEffect(() => {
    if (user) {
      localStorage.setItem('userInfo', JSON.stringify(user));
    }
  }, [user]);

  const login = async (email, password) => {
    const { data } = await axiosInstance.post('/auth/login/', { email, password });
    const tokens = JSON.parse(data.tokens.replace(/'/g, '"'));
    const userInfo = {
      id: data.id,
      email: data.email,
      username: data.username,
      role: data.role,
    };

    localStorage.setItem('accessToken', tokens.access);
    localStorage.setItem('refreshToken', tokens.refresh);
    localStorage.setItem('userInfo', JSON.stringify(userInfo));
    setUser(userInfo);
    return userInfo;
  };

  const register = async (formData, userType) => {
    try {
      const registrationData = normalizeRegisterPayload(formData, userType);
      const { data } = await axiosInstance.post('/auth/register/', registrationData);

      notification.success({
        message: 'Registration Successful',
        description: `Welcome, ${data.username}! Your standalone workspace is ready.`,
      });

      return data;
    } catch (error) {
      notification.error({
        message: 'Registration Failed',
        description: error?.response?.data?.errors
          ? Object.values(error.response.data.errors).flat().join(', ')
          : error.message || 'Unable to create your account.',
      });
      throw error;
    }
  };

  const verifyToken = async () => {
    const token = localStorage.getItem('accessToken');
    if (!token) {
      return false;
    }
    try {
      await axiosInstance.post('/auth/verify-token', { token });
      return true;
    } catch (error) {
      logout();
      return false;
    }
  };

  const forgotPassword = async (email) => {
    await axiosInstance.post('/auth/request-reset-email/', { email });
    notification.success({
      message: 'Reset Link Generated',
      description: 'In standalone mode, you can proceed directly to the reset screen.',
    });
  };

  const resetPassword = async (token, newPassword, confirmPassword) => {
    if (newPassword !== confirmPassword) {
      notification.error({
        message: 'Error',
        description: 'Passwords do not match.',
      });
      return;
    }

    await axiosInstance.post(`/auth/password-reset/${token}`, {
      token,
      password: newPassword,
      confirm_password: confirmPassword,
    });

    notification.success({
      message: 'Password Reset Successful',
      description: 'Your password has been updated.',
    });
  };

  const logout = async () => {
    try {
      await axiosInstance.post('/auth/logout/');
    } catch (error) {}
    localStorage.removeItem('userInfo');
    localStorage.removeItem('accessToken');
    localStorage.removeItem('refreshToken');
    localStorage.removeItem('organization_id');
    setUser(null);
  };

  // eslint-disable-next-line react-hooks/exhaustive-deps
  const value = useMemo(
    () => ({
      user,
      isAuthenticated: Boolean(user),
      login,
      register,
      verifyToken,
      forgotPassword,
      resetPassword,
      logout,
    }),
    [user]
  );

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
};

export { AuthProvider, AuthContext };

const path = require('path');
const { promises: fsp } = require('fs');
const crypto = require('crypto');

// HTTPS redirect middleware for production
const enforceHTTPS = (req, res, next) => {
  if (process.env.NODE_ENV === 'production' && req.headers['x-forwarded-proto'] !== 'https') {
    return res.redirect(301, `https://${req.headers.host}${req.url}`);
  }
  next();
};

module.exports = async function (context) {
  const { req, res } = context;
  const requestPath = req.path.replace(/^\//, '') || 'index.html';
  const filePath = path.join(__dirname, 'dist', requestPath);

  const mimeTypes = {
    '.html': 'text/html',
    '.js': 'text/javascript',
    '.css': 'text/css',
    '.json': 'application/json',
    '.png': 'image/png',
    '.jpg': 'image/jpeg',
    '.gif': 'image/gif',
    '.svg': 'image/svg+xml',
    '.ico': 'image/x-icon',
    '.txt': 'text/plain',
    '.map': 'application/json'
  };

  try {
    // Try to serve the requested file if it exists
    try {
      const stat = await fsp.stat(filePath);
      if (stat.isFile()) {
        const ext = path.extname(filePath).toLowerCase();
        const contentType = mimeTypes[ext] || 'application/octet-stream';
        const content = await fsp.readFile(filePath);
        res.setHeader('Content-Type', contentType);
        res.setHeader('Cache-Control', 'public, max-age=31536000');
        // Security Headers
        res.setHeader('X-Frame-Options', 'DENY');
        res.setHeader('X-Content-Type-Options', 'nosniff');
        res.setHeader('X-XSS-Protection', '1; mode=block');
        res.setHeader('Referrer-Policy', 'strict-origin-when-cross-origin');
        res.setHeader('Permissions-Policy', 'geolocation=(), microphone=(), camera=()');
        // HSTS - only in production
        if (process.env.NODE_ENV === 'production') {
          res.setHeader('Strict-Transport-Security', 'max-age=31536000; includeSubDomains; preload');
        }
        res.setHeader('Content-Security-Policy', "default-src 'self'; script-src 'self' 'unsafe-inline' 'unsafe-eval'; style-src 'self' 'unsafe-inline'; img-src 'self' data: https:; font-src 'self' data:; connect-src 'self' https://cloud.appwrite.io https://*.appwrite.io; frame-ancestors 'none'; base-uri 'self'; form-action 'self';");
        res.send(content);
        return;
      }
    } catch (err) {
      // File not found or not a file, fall through to SPA fallback
    }

    // Fallback to index.html for SPA routing
    const indexPath = path.join(__dirname, 'dist', 'index.html');
    let indexContent = await fsp.readFile(indexPath);

    // Inject CSP nonce for inline scripts in production
    if (process.env.NODE_ENV === 'production') {
      const nonce = require('crypto').randomBytes(16).toString('hex');
      indexContent = indexContent.replace(
        /<head>/i,
        `<head><meta http-equiv="Content-Security-Policy" content="default-src 'self'; script-src 'self' 'nonce-${nonce}'; style-src 'self' 'unsafe-inline'; img-src 'self' data: https:; font-src 'self' data:; connect-src 'self' https://cloud.appwrite.io https://*.appwrite.io; frame-ancestors 'none'; base-uri 'self'; form-action 'self';"><meta name="csrf-token" content="${nonce}">`
      );
    }

    res.setHeader('Content-Type', 'text/html');
    // Security headers for SPA fallback
    res.setHeader('X-Frame-Options', 'DENY');
    res.setHeader('X-Content-Type-Options', 'nosniff');
    res.setHeader('X-XSS-Protection', '1; mode=block');
    res.setHeader('Referrer-Policy', 'strict-origin-when-cross-origin');
    res.setHeader('Permissions-Policy', 'geolocation=(), microphone=(), camera=()');
    if (process.env.NODE_ENV === 'production') {
      res.setHeader('Strict-Transport-Security', 'max-age=31536000; includeSubDomains; preload');
    }
    res.send(indexContent);

  } catch (error) {
    res.statusCode = 500;
    res.send(`Error: ${error.message}`);
  }
};

